SET NAMES utf8mb4;

UPDATE article_translations SET
  content_blocks = '[{"type": "subheading", "color": "text-fuchsia-300", "label": "Material suplementario", "small": true}, {"type": "heading", "label": "1. Video con un ejemplo de captaci\\u00f3n cercana del campo est\\u00e9reo del bandone\\u00f3n"}, {"url": "https://player.vimeo.com/video/1188180014?badge=0&autopause=0&player_id=0&app_id=58479", "type": "video"}, {"text": "La ubicaci\\u00f3n de los micr\\u00f3fonos a una distancia cercana y constante permite preservar el campo est\\u00e9reo din\\u00e1mico del bandone\\u00f3n, ya que la posici\\u00f3n de las fuentes sonoras cambia continuamente con el movimiento de los fuelles.", "type": "text", "small": true}, {"type": "heading", "label": "2. Selecci\\u00f3n de sonidos del banco sonoro"}, {"url": "https://res.cloudinary.com/djxcomnwb/video/upload/v1740569103/extended-bandoneon/soundbank/mp3/uf0ldgemfjelhjrijwhf.mp3", "type": "sound", "label": "Vibrato de aire"}, {"url": "https://res.cloudinary.com/djxcomnwb/video/upload/v1740660384/extended-bandoneon/soundbank/mp3/ccl96y9ce9j4hhuoygwb.mp3", "type": "sound", "label": "Cluster con la mano derecha"}, {"url": "https://www.extendedbandoneon.com/soundbank", "type": "link", "label": "Versi\\u00f3n ampliada del banco sonoro disponible en:"}, {"type": "heading", "label": "3. Ejemplos en video y audio de una sesi\\u00f3n de grabaci\\u00f3n de sonidos perif\\u00e9ricos y descartados"}, {"text": "Este video documenta una sesi\\u00f3n de grabaci\\u00f3n centrada en sonidos perif\\u00e9ricos y descartados del bandone\\u00f3n: sonidos de la madera, de los fuelles, percusiones sobre distintos materiales, sonidos mec\\u00e1nicos del interior del instrumento, sonidos de aire con tono y ruidos corporales incidentales. Las im\\u00e1genes se presentan en velocidad acelerada y los sonidos son deliberadamente sutiles, en ocasiones casi imperceptibles. El archivo de audio re\\u00fane una selecci\\u00f3n de muestras sonoras extra\\u00eddas de la misma sesi\\u00f3n de grabaci\\u00f3n, registradas mediante los micr\\u00f3fonos DPA 4099 Core.", "type": "text"}, {"url": "https://player.vimeo.com/video/1187188364", "type": "video"}, {"url": "https://res.cloudinary.com/djxcomnwb/video/upload/v1777536970/soundbank/mp3/rsbcbddofge0xdapjfl7.mp3", "type": "sound", "label": "Sesi\\u00f3n de grabaci\\u00f3n: sonidos seleccionados"}, {"url": "https://www.extendedbandoneon.com/soundbank", "type": "link", "label": "Versi\\u00f3n ampliada del banco sonoro disponible en:"}, {"type": "heading", "label": "4. Diferencias observadas en las respuestas generadas por distintos sonidos del bandone\\u00f3n durante los procesos de entrenamiento e interacci\\u00f3n."}, {"rows": [["Air Sounds - Long", "Medium", "Variable"], ["Air Sound - Short", "High", "Consistent"], ["Air Sound - Vibrato", "Medium", "Variable"], ["Bellows Sounds - Percussive - Bellow Shake with Air Sound", "Medium", "Unstable"], ["Single Button Sound", "High", "Consistent"], ["Buttons Sounds - Textural", "High", "Consistent"], ["Tapping on wood casing with fingertips", "High", "Variable"], ["Tapping on wood casing with fingernails", "High", "Variable"], ["Friction of bellows and clothes - e.g. bellows and trousers", "Medium", "Variable"], ["High Pitched Notes - Long", "Medium", "Inconsistent"], ["High Pitched Notes - Short", "Medium", "Variable"], ["Medium Pitched Notes - Long and Short", "Medium", "Inconsistent"], ["Medium Pitched Notes - Long and Short", "Low", "Inconsistent"], ["Clusters - Singled and Doubled Handed", "Low", "Inconsistent"]], "type": "table", "headers": ["Sound Type", "Recognisability (System)", "System Response"]}, {"type": "heading", "label": "5. Documentaci\\u00f3n de Neons & Neutrals"}, {"type": "subheading", "label": "Sobre el proyecto"}, {"text": "Neons & Neutrals es una performance solista para bandone\\u00f3n y electr\\u00f3nica en vivo que explora la transformaci\\u00f3n del instrumento a trav\\u00e9s de t\\u00e9cnicas extendidas, movimiento y tecnolog\\u00eda. La obra aborda el bandone\\u00f3n como un instrumento aumentado dentro de un entorno multicanal, investigando c\\u00f3mo los instrumentos tradicionales pueden expandirse y transformarse mediante su interacci\\u00f3n con procesos electr\\u00f3nicos.", "type": "text"}, {"type": "subheading", "label": "Neons & Neutrals \\u2013 Sesi\\u00f3n de pr\\u00e1ctica (bandone\\u00f3n y electr\\u00f3nica en vivo) - Documentaci\\u00f3n en video", "centered": true}, {"text": "Lugar: Black Box, Centro de M\\u00fasica de Helsinki, Academia Sibelius, Finlandia\\nFecha: 18.3.2025", "type": "text", "centered": true}, {"url": "https://www.youtube.com/embed/qh4tQXV7MMI", "type": "video"}, {"type": "subheading", "label": "Neons & Neutrals \\u2013 Fragmentos de la performance (bandone\\u00f3n y electr\\u00f3nica en vivo) - Documentaci\\u00f3n en video", "centered": true, "spaceBefore": true}, {"text": "Lugar: Black Box, Centro de M\\u00fasica de Helsinki, Academia Sibelius, Finlandia\\nFecha: 18.3.2025", "type": "text", "centered": true}, {"url": "https://www.youtube.com/embed/54pOZawlfiw", "type": "video"}, {"type": "heading", "label": "6. Documentaci\\u00f3n de Scratched Surfaces"}, {"type": "subheading", "label": "Sobre el proyecto"}, {"text": "Scratched Surfaces es una instalaci\\u00f3n sonora performativa que explora los elementos sonoros sutiles del bandone\\u00f3n. Estos sonidos se distribuyen a trav\\u00e9s de un sistema de ocho canales, ocho conos de altavoz y dos amplificadores de guitarra, acompa\\u00f1ados por una proyecci\\u00f3n de video en una tablet que re\\u00fane im\\u00e1genes provenientes de la pr\\u00e1ctica art\\u00edstica de la autora. La obra forma parte del proyecto de investigaci\\u00f3n doctoral Bandoneon Resonances.", "type": "text"}, {"type": "subheading", "label": "Scratched Surfaces \\u2013 Intervenci\\u00f3n performativa durante la instalaci\\u00f3n sonora - Documentaci\\u00f3n en video", "centered": true}, {"text": "Lugar: Black Box, Centro de M\\u00fasica de Helsinki, Academia Sibelius, Finlandia\\nFecha: 24.11.2025", "type": "text", "centered": true}, {"url": "https://www.youtube.com/embed/aacsZoYssg0", "type": "video"}, {"url": "https://mekrapov.com/scratched-surfaces", "type": "link", "label": "M\\u00e1s informaci\\u00f3n sobre Scratched Surfaces disponible en:"}]'
WHERE article_id = 2 AND locale = 'es';
